 51→  let additionalArgs: string[] = [];
 52→  let aiLoop = false;
 53→
 54→  // Find if there's a "--" separator for additional args
 55→  const separatorIndex = args.indexOf("--");
 56→  const mainArgs = separatorIndex >= 0 ? args.slice(0, separatorIndex) : args;
 57→  additionalArgs = separatorIndex >= 0 ? args.slice(separatorIndex + 1) : [];
 58→
 59→  for (let i = 0; i < mainArgs.length; i++) {
 60→    const arg = mainArgs[i];
 61→    if (arg === "-p" || arg === "--port") {
 62→      port = mainArgs[i + 1] || port;
 63→      i++;
 64→    } else if (arg === "-k" || arg === "--key") {
 65→      key = mainArgs[i + 1] || key;
 66→      i++;
 67→    } else if (arg === "-m" || arg === "--msg") {
 68→      msg = mainArgs[i + 1] || msg;
 69→      i++;
 70→    } else if (arg === "--headless") {
 71→      headless = true;
 72→    } else if (arg === "--dry-run") {
 73→      dryRun = true;
 74→    } else if (arg === "--restore") {
 75→      restore = true;
 76→    } else if (arg === "-y" || arg === "--yes") {
 77→      yes = true;
 78→    } else if (arg === "--yolo") {
 79→      yolo = true;
 80→    } else if (arg === "--system-prompt") {
 81→      systemPrompt = mainArgs[i + 1] || systemPrompt;
 82→      i++;
 83→    } else if (arg === "--system-prompt-file") {
 84→      systemPromptFile = mainArgs[i + 1] || systemPromptFile;
 85→      i++;
 86→    } else if (arg === "--ai-loop") {
 87→      aiLoop = true;
 88→    }
 89→  }
 90→
 91→  return {
 92→    command,
 93→    port,
 94→    key,
 95→    msg,
 96→    headless,
 97→    dryRun,
 98→    restore,
 99→    yes,
100→    yolo,
101→    systemPrompt,
102→    systemPromptFile,
103→    additionalArgs,
104→    aiLoop,
105→  };
106→}
