377→function McpServer({ port, apiKey }: { port: string; apiKey: string }) {
378→  const [status, setStatus] = useState<"starting" | "running" | "error">("starting");
379→  const [error, setError] = useState<string | null>(null);
380→
381→  useEffect(() => {
382→    process.env.PORT = port;
383→    process.env.API_KEY = apiKey;
384→
385→    import("./http.ts")
386→      .then(() => {
387→        setStatus("running");
388→      })
389→      .catch((err) => {
390→        setStatus("error");
391→        setError(err.message);
392→      });
393→  }, [port, apiKey]);
394→
395→  if (status === "error") {
396→    return (
397→      <Box flexDirection="column" padding={1}>
398→        <Text color="red">✗ Failed to start MCP server</Text>
399→        {error && <Text dimColor>{error}</Text>}
400→      </Box>
401→    );
402→  }
403→
404→  if (status === "starting") {
405→    return (
406→      <Box padding={1}>
407→        <Spinner label="Starting MCP server..." />
408→      </Box>
409→    );
410→  }
411→
412→  return (
413→    <Box flexDirection="column" padding={1}>
414→      <Box>
415→        <Text color="green">✓ </Text>
416→        <Text>MCP HTTP server running on </Text>
417→        <Text color="cyan" bold>
418→          http://localhost:{port}/mcp
419→        </Text>
420→      </Box>
421→      {apiKey && <Text dimColor>API key authentication enabled</Text>}
422→      <Text dimColor>Press Ctrl+C to stop</Text>
423→    </Box>
424→  );
425→}
