545→function App({ args }: { args: ParsedArgs }) {
546→  const {
547→    command,
548→    port,
549→    key,
550→    msg,
551→    headless,
552→    dryRun,
553→    restore,
554→    yes,
555→    yolo,
556→    systemPrompt,
557→    systemPromptFile,
558→    additionalArgs,
559→    aiLoop,
560→  } = args;
561→
562→  switch (command) {
563→    case "setup":
564→      return <Setup dryRun={dryRun} restore={restore} yes={yes} />;
565→    case "mcp":
566→      return <McpServer port={port} apiKey={key} />;
567→    case "claude":
568→      return <ClaudeRunner msg={msg} headless={headless} additionalArgs={additionalArgs} />;
569→    case "worker":
570→      return (
571→        <WorkerRunner
572→          prompt={msg}
573→          yolo={yolo}
574→          systemPrompt={systemPrompt}
575→          systemPromptFile={systemPromptFile}
576→          additionalArgs={additionalArgs}
577→          aiLoop={aiLoop}
578→        />
579→      );
580→    case "lead":
581→      return (
582→        <LeadRunner
583→          prompt={msg}
584→          yolo={yolo}
585→          systemPrompt={systemPrompt}
586→          systemPromptFile={systemPromptFile}
587→          additionalArgs={additionalArgs}
588→          aiLoop={aiLoop}
589→        />
590→      );
591→    case "version":
592→      return <Version />;
593→    case "help":
594→    case undefined:
595→      return <Help />;
596→    default:
597→      return <UnknownCommand command={command} />;
598→  }
599→}
600→
601→const args = parseArgs(process.argv.slice(2));
602→
603→// Handle non-UI commands separately
604→if (args.command === "hook") {
605→  runHook();
606→} else if (args.command === "artifact") {
607→  // Pass all args after "artifact" directly
608→  const artifactArgs = process.argv.slice(process.argv.indexOf("artifact") + 1);
609→  const { runArtifact } = await import("./commands/artifact");
610→  await runArtifact(artifactArgs[0] || "help", {
611→    additionalArgs: artifactArgs.slice(1),
612→    port: args.port,
613→    key: args.key,
614→  });
615→} else {
616→  render(<App args={args} />);
617→}
