287→
288→        addLog("Non-interactive mode: using environment variables");
289→        setState((s) => ({
290→          ...s,
291→          step: "updating",
292→          isGitRepo,
293→          token,
294→          agentId: agentId || "",
295→        }));
296→        return;
297→      }
298→
299→      setState((s) => ({
300→        ...s,
