            </Text>
          </Box>
        )}
        <Logs logs={state.logs} />
        <Box marginTop={1}>
          <Text color="green">Onboard complete!</Text>
        </Box>
      </Box>
    );
  }

  // Placeholder for unimplemented steps
  return (
    <Box flexDirection="column" padding={1}>
