// Restore cursor on exit
const restoreCursor = () => process.stdout.write("\x1B[?25h");
process.on("exit", restoreCursor);
process.on("SIGINT", () => {
  restoreCursor();
  process.exit(0);
});

interface ParsedArgs {
  command: string | undefined;
  port: string;
  key: string;
  msg: string;
  headless: boolean;
  dryRun: boolean;
  restore: boolean;
  yes: boolean;
  yolo: boolean;
  systemPrompt: string;
  systemPromptFile: string;
  additionalArgs: string[];
  aiLoop: boolean;
  preset: string;
}

function parseArgs(args: string[]): ParsedArgs {
  const command = args[0] && !args[0].startsWith("-") ? args[0] : undefined;
  let port = process.env.PORT || "3013";
  let key = process.env.API_KEY || "";
  let msg = "";
  let headless = false;
  let dryRun = false;
  let restore = false;
  let yes = false;
  let yolo = false;
  let systemPrompt = "";
  let systemPromptFile = "";
  let additionalArgs: string[] = [];
  let aiLoop = false;
  let preset = "";

  // Find if there's a "--" separator for additional args
  const separatorIndex = args.indexOf("--");
  const mainArgs = separatorIndex >= 0 ? args.slice(0, separatorIndex) : args;
  additionalArgs = separatorIndex >= 0 ? args.slice(separatorIndex + 1) : [];

  for (let i = 0; i < mainArgs.length; i++) {
    const arg = mainArgs[i];
    if (arg === "-p" || arg === "--port") {
      port = mainArgs[i + 1] || port;
      i++;
    } else if (arg === "-k" || arg === "--key") {
      key = mainArgs[i + 1] || key;
      i++;
    } else if (arg === "-m" || arg === "--msg") {
      msg = mainArgs[i + 1] || msg;
      i++;
    } else if (arg === "--headless") {
      headless = true;
    } else if (arg === "--dry-run") {
      dryRun = true;
    } else if (arg === "--restore") {
      restore = true;
    } else if (arg === "-y" || arg === "--yes") {
      yes = true;
    } else if (arg === "--yolo") {
      yolo = true;
    } else if (arg === "--system-prompt") {
      systemPrompt = mainArgs[i + 1] || systemPrompt;
      i++;
    } else if (arg === "--system-prompt-file") {
      systemPromptFile = mainArgs[i + 1] || systemPromptFile;
      i++;
    } else if (arg === "--ai-loop") {
      aiLoop = true;
    } else if (arg === "--preset") {
      preset = mainArgs[i + 1] || preset;
      i++;
    } else if (arg.startsWith("--preset=")) {
      preset = arg.split("=")[1] || "";
    }
  }

  return {
    command,
    port,
    key,
    msg,
    headless,
    dryRun,
    restore,
    yes,
    yolo,
    systemPrompt,
    systemPromptFile,
    additionalArgs,
    aiLoop,
  };
}

