function McpServer({ port, apiKey }: { port: string; apiKey: string }) {
  const [status, setStatus] = useState<"starting" | "running" | "error">("starting");
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    process.env.PORT = port;
    process.env.API_KEY = apiKey;

    import("./http.ts")
      .then(() => {
        setStatus("running");
      })
      .catch((err) => {
        setStatus("error");
        setError(err.message);
      });
  }, [port, apiKey]);

  if (status === "error") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text color="red">✗ Failed to start MCP server</Text>
        {error && <Text dimColor>{error}</Text>}
      </Box>
    );
  }

  if (status === "starting") {
    return (
      <Box padding={1}>
        <Spinner label="Starting MCP server..." />
      </Box>
    );
  }

  return (
    <Box flexDirection="column" padding={1}>
      <Box>
        <Text color="green">✓ </Text>
        <Text>MCP HTTP server running on </Text>
        <Text color="cyan" bold>
          http://localhost:{port}/mcp
        </Text>
      </Box>
      {apiKey && <Text dimColor>API key authentication enabled</Text>}
      <Text dimColor>Press Ctrl+C to stop</Text>
    </Box>
  );
}

interface ClaudeRunnerProps {
  msg: string;
  headless: boolean;
  additionalArgs: string[];
}

function ClaudeRunner({ msg, headless, additionalArgs }: ClaudeRunnerProps) {
  const { exit } = useApp();

  useEffect(() => {
    runClaude({
      msg,
      headless,
      additionalArgs,
    })
      .then(() => exit())
      .catch((err) => exit(err));
  }, [msg, headless, additionalArgs, exit]);

  return null;
}

interface RunnerProps {
  prompt: string;
  yolo: boolean;
  systemPrompt: string;
  systemPromptFile: string;
  additionalArgs: string[];
  aiLoop: boolean;
}

function WorkerRunner({
  prompt,
  yolo,
  systemPrompt,
  systemPromptFile,
  additionalArgs,
  aiLoop,
}: RunnerProps) {
  const { exit } = useApp();

  useEffect(() => {
    runWorker({
      prompt: prompt || undefined,
      yolo,
      systemPrompt: systemPrompt || undefined,
      systemPromptFile: systemPromptFile || undefined,
      additionalArgs,
      logsDir: "./logs",
      aiLoop,
    }).catch((err) => {
      console.error("[error] Worker encountered an error:", err);
      exit(err);
    });
    // Note: runWorker runs indefinitely, so we don't call exit() on success
  }, [prompt, yolo, systemPrompt, systemPromptFile, additionalArgs, aiLoop, exit]);

  return null;
}

function LeadRunner({
  prompt,
  yolo,
  systemPrompt,
  systemPromptFile,
  additionalArgs,
  aiLoop,
}: RunnerProps) {
  const { exit } = useApp();

