    } else if (arg === "--preset") {
      preset = mainArgs[i + 1] || preset;
      i++;
    } else if (arg.startsWith("--preset=")) {
      preset = arg.split("=")[1] || "";
    }
  }

  return {
    command,
    port,
    key,
    msg,
    headless,
    dryRun,
    restore,
    yes,
    yolo,
    systemPrompt,
    systemPromptFile,
