  | "post_task"
  | "done"
  | "error";

export interface OnboardState {
  step: OnboardStep;
  deployType: "local" | "remote";
  presetId: string | null;
  services: ServiceEntry[];
  harness: "claude" | "pi";
  claudeOAuthToken: string;
  apiKey: string;
  agentIds: Record<string, string>;
  integrations: {
    github: boolean;
    slack: boolean;
    gitlab: boolean;
