import { Select, TextInput } from "@inkjs/ui";
import { Box, Text } from "ink";
import { useState } from "react";
import type { StepProps } from "../types.ts";

type SubStep = "ask" | "input" | "sending" | "sent";

export function PostTaskStep({ state, addLog, goToNext, goToError }: StepProps) {
  const [subStep, setSubStep] = useState<SubStep>("ask");
  const [sentTask, setSentTask] = useState("");

  const leadService = state.services.find((s) => s.isLead);
  const leadName = leadService ? "lead" : Object.keys(state.agentIds)[0] || "";
  const leadAgentId = state.agentIds[leadName] || "";

  if (subStep === "ask") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text bold>Send your first task to the swarm?</Text>
        <Box marginTop={1}>
          <Select
            options={[
              { label: "Yes — send a task", value: "yes" },
              { label: "Skip", value: "skip" },
            ]}
            onChange={(value) => {
              if (value === "yes") {
                setSubStep("input");
              } else {
                goToNext();
              }
            }}
          />
        </Box>
      </Box>
    );
  }

  if (subStep === "input") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text bold>What should the swarm do?</Text>
        <Box marginTop={1}>
          <TextInput
            placeholder="Say hello to the swarm"
            onSubmit={async (value) => {
              const task = value.trim() || "Say hello to the swarm";
              setSubStep("sending");
              setSentTask(task);
              try {
                const res = await fetch("http://localhost:3013/api/tasks", {
                  method: "POST",
                  headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${state.apiKey}`,
                  },
                  body: JSON.stringify({
                    task,
                    agentId: leadAgentId || undefined,
                  }),
                });
                if (!res.ok) {
                  const text = await res.text();
                  addLog(`Task API returned ${res.status}: ${text}`);
                } else {
                  addLog("Task sent successfully");
                }
              } catch (err) {
                addLog(`Failed to send task: ${err}`);
              }
              setSubStep("sent");
            }}
          />
        </Box>
      </Box>
    );
  }

  if (subStep === "sending" || subStep === "sent") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text color="green">
          {"✓"} Task sent: "{sentTask}"
        </Text>
        <Text dimColor>Check the dashboard to see it get picked up.</Text>
        {subStep === "sent" && <DoneTimer goToNext={goToNext} />}
      </Box>
    );
  }

  return null;
}

function DoneTimer({ goToNext }: { goToNext: () => void }) {
  const [ready, setReady] = useState(false);
  // biome-ignore lint/correctness/useExhaustiveDependencies: one-shot timer
  useState(() => {
    setTimeout(() => {
      setReady(true);
      goToNext();
    }, 1000);
  });
  return null;
}

import { Select, Spinner } from "@inkjs/ui";
import { Box, Text } from "ink";
import { useEffect, useRef, useState } from "react";
import type { StepProps } from "../types.ts";

type StartStatus = "starting" | "success" | "failed";

export function StartStep({ state, addLog, goToNext, goToError }: StepProps) {
  const [status, setStatus] = useState<StartStatus>("starting");
  const [errorMsg, setErrorMsg] = useState("");
  const executed = useRef(false);

  useEffect(() => {
    if (executed.current) return;
    executed.current = true;

    const run = async () => {
      addLog("Running docker compose up -d...");
      try {
        const result = await Bun.$`docker compose --env-file .env up -d`
          .cwd(state.outputDir)
          .quiet();

        if (result.exitCode === 0) {
          addLog("Docker stack started successfully");
          setStatus("success");
        } else {
          const stderr = result.stderr.toString().trim();
          setErrorMsg(stderr || "docker compose up failed");
          setStatus("failed");
        }
      } catch (err) {
        setErrorMsg(err instanceof Error ? err.message : String(err));
        setStatus("failed");
      }
    };

    run();
  }, [state.outputDir, addLog]);

  useEffect(() => {
    if (status === "success") {
      const timer = setTimeout(() => goToNext(), 500);
      return () => clearTimeout(timer);
    }
  }, [status, goToNext]);

  if (status === "starting") {
    return (
      <Box padding={1}>
        <Spinner label="Starting Docker stack..." />
      </Box>
    );
  }

  if (status === "success") {
    return (
      <Box padding={1}>
        <Text color="green">{"✓"} Docker stack started</Text>
      </Box>
    );
  }

  return (
    <Box flexDirection="column" padding={1}>
      <Text color="red">{"✗"} Failed to start Docker stack</Text>
      <Text dimColor>{errorMsg}</Text>
      <Box marginTop={1}>
        <Select
          options={[
            { label: "Retry", value: "retry" },
            { label: "View logs (docker compose logs)", value: "logs" },
            { label: "Skip", value: "skip" },
          ]}
          onChange={async (value) => {
            if (value === "retry") {
              executed.current = false;
              setStatus("starting");
              setErrorMsg("");
            } else if (value === "logs") {
              try {
                const logs = await Bun.$`docker compose logs --tail 30`
                  .cwd(state.outputDir)
                  .quiet();
                addLog(logs.text());
              } catch {
                addLog("Failed to fetch logs");
              }
            } else {
              goToNext();
            }
          }}
        />
      </Box>
    </Box>
  );
}

