    case "harness":
      return <HarnessStep {...props} />;
    case "harness_credentials":
      return <HarnessCredentialsStep {...props} />;
    case "core_credentials":
      return <CoreCredentialsStep {...props} />;
    case "integration_menu":
      return <IntegrationMenuStep {...props} />;
