    if (await envFile.exists()) {
      const envContent = await envFile.text();
      const match = envContent.match(/^API_KEY=(.+)$/m);
      if (match?.[1]) {
        existingToken = match[1].trim();
        addLog("Found API_KEY in .env");
      }
    }
  } catch {
    // Ignore errors reading .env
  }
}

