import { Select, TextInput } from "@inkjs/ui";
import { Box, Text } from "ink";
import { useEffect, useRef, useState } from "react";
import type { StepProps } from "../types.ts";

type SubStep = "ask" | "input" | "sending" | "sent";

export function PostTaskStep({ state, addLog, goToNext }: StepProps) {
  const [subStep, setSubStep] = useState<SubStep>("ask");
  const [sentTask, setSentTask] = useState("");

  const leadService = state.services.find((s) => s.isLead);
  const leadName = leadService ? "lead" : Object.keys(state.agentIds)[0] || "";
  const leadAgentId = state.agentIds[leadName] || "";

  if (subStep === "ask") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text bold>Send your first task to the swarm?</Text>
        <Box marginTop={1}>
          <Select
            options={[
              { label: "Yes — send a task", value: "yes" },
              { label: "Skip", value: "skip" },
            ]}
            onChange={(value) => {
              if (value === "yes") {
                setSubStep("input");
              } else {
                goToNext();
              }
            }}
          />
        </Box>
      </Box>
    );
  }

  if (subStep === "input") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text bold>What should the swarm do?</Text>
        <Box marginTop={1}>
          <TextInput
            placeholder="Say hello to the swarm"
            onSubmit={async (value) => {
              const task = value.trim() || "Say hello to the swarm";
              setSubStep("sending");
              setSentTask(task);
              try {
                const res = await fetch("http://localhost:3013/api/tasks", {
                  method: "POST",
                  headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${state.apiKey}`,
                  },
                  body: JSON.stringify({
                    task,
                    agentId: leadAgentId || undefined,
                  }),
                });
                if (!res.ok) {
                  const text = await res.text();
                  addLog(`Task API returned ${res.status}: ${text}`);
                } else {
                  addLog("Task sent successfully");
                }
              } catch (err) {
                addLog(`Failed to send task: ${err}`);
              }
              setSubStep("sent");
            }}
          />
        </Box>
      </Box>
    );
  }

  if (subStep === "sending" || subStep === "sent") {
    return (
      <Box flexDirection="column" padding={1}>
        <Text color="green">
          {"✓"} Task sent: "{sentTask}"
        </Text>
        <Text dimColor>Check the dashboard to see it get picked up.</Text>
        {subStep === "sent" && <DoneTimer goToNext={goToNext} />}
      </Box>
    );
  }

  return null;
}

function DoneTimer({ goToNext }: { goToNext: () => void }) {
  const executed = useRef(false);
  useEffect(() => {
    if (executed.current) return;
    executed.current = true;
    const timer = setTimeout(() => goToNext(), 1000);
    return () => clearTimeout(timer);
  }, [goToNext]);
  return null;
}

import { expandServices } from "./service-names.ts";
import type { OnboardState } from "./types.ts";

// Docker Compose env var references use ${VAR} syntax which triggers biome's
// noTemplateCurlyInString rule. We collect them via a helper to keep the
// suppression comments in one place.

// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_API_KEY = "      - API_KEY=${API_KEY}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_SLACK_BOT_TOKEN = "      - SLACK_BOT_TOKEN=${SLACK_BOT_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_SLACK_APP_TOKEN = "      - SLACK_APP_TOKEN=${SLACK_APP_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_CLAUDE_OAUTH = "      - CLAUDE_CODE_OAUTH_TOKEN=${CLAUDE_CODE_OAUTH_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_ANTHROPIC_KEY = "      - ANTHROPIC_API_KEY=${ANTHROPIC_API_KEY}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_GITHUB_TOKEN = "      - GITHUB_TOKEN=${GITHUB_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_GITHUB_EMAIL = "      - GITHUB_EMAIL=${GITHUB_EMAIL}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_GITHUB_NAME = "      - GITHUB_NAME=${GITHUB_NAME}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_GITLAB_TOKEN = "      - GITLAB_TOKEN=${GITLAB_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_GITLAB_EMAIL = "      - GITLAB_EMAIL=${GITLAB_EMAIL}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_SENTRY_AUTH_TOKEN = "      - SENTRY_AUTH_TOKEN=${SENTRY_AUTH_TOKEN}";
// biome-ignore lint/suspicious/noTemplateCurlyInString: Docker Compose env var syntax
const ENV_SENTRY_ORG = "      - SENTRY_ORG=${SENTRY_ORG}";

/**
 * Generate a docker-compose.yml string from onboard wizard state.
 * Builds the YAML as plain strings (no YAML library) following the pattern
 * used in templates-ui/src/lib/compose-generator.ts.
 */
export function generateCompose(state: OnboardState): string {
  const expanded = expandServices(state.services, state.agentIds);
  const lines: string[] = [];

  // Header
  lines.push("# Docker Compose for Agent Swarm");
  lines.push("# Generated by `agent-swarm onboard`");
  lines.push("#");
  lines.push("# Usage:");
  lines.push("#   docker compose --env-file .env up -d");
  lines.push("");
  lines.push("services:");

  // ── API service ──
  lines.push("  swarm-api:");
  lines.push('    image: "ghcr.io/desplega-ai/agent-swarm:latest"');
  lines.push("    container_name: swarm-api");
  lines.push("    pull_policy: always");
  lines.push("    stop_grace_period: 60s");
  lines.push("");
  const port = state.apiPort || 3013;

  lines.push("    environment:");
  lines.push(ENV_API_KEY);
  lines.push(`      - MCP_BASE_URL=http://localhost:${port}`);
  lines.push("      - APP_URL=http://localhost:5274");

  if (state.integrations.slack) {
    lines.push("      - SLACK_DISABLE=false");
    lines.push(ENV_SLACK_BOT_TOKEN);
    lines.push(ENV_SLACK_APP_TOKEN);
  }

  if (state.integrations.github) {
    lines.push("      - GITHUB_DISABLE=false");
  }

  lines.push("");
  lines.push("    ports:");
  lines.push(`      - "${port}:3013"`);
  lines.push("");
  lines.push("    volumes:");
  lines.push("      - swarm_data:/app/data");
  lines.push("");
  lines.push("    healthcheck:");
  lines.push('      test: ["CMD-SHELL", "curl -f http://localhost:3013/health || exit 1"]');
  lines.push("      interval: 10s");
  lines.push("      timeout: 5s");
  lines.push("      retries: 3");
  lines.push("      start_period: 15s");
  lines.push("");
  lines.push("    restart: unless-stopped");

  // ── Agent services ──
  let nextPort = 3201;

  for (const svc of expanded) {
    const port = nextPort++;
    const agentRole = svc.entry.isLead ? "lead" : "worker";
    const agentName =
      svc.entry.count > 1 ? `${svc.entry.displayName} ${svc.index + 1}` : svc.entry.displayName;

    lines.push("");
    lines.push(`  ${svc.name}:`);
    lines.push('    image: "ghcr.io/desplega-ai/agent-swarm-worker:latest"');
    lines.push(`    container_name: ${svc.containerName}`);
    lines.push("    pull_policy: always");
    lines.push("    stop_grace_period: 60s");
    lines.push("");
    lines.push("    depends_on:");
    lines.push("      swarm-api:");
    lines.push("        condition: service_healthy");
    lines.push("");
    lines.push("    environment:");
    if (state.credentialType === "api_key") {
      lines.push(ENV_ANTHROPIC_KEY);
    } else {
      lines.push(ENV_CLAUDE_OAUTH);
    }
    lines.push(ENV_API_KEY);
    lines.push(`      - AGENT_ID=${svc.agentId}`);
    lines.push(`      - AGENT_NAME=${agentName}`);
    lines.push(`      - AGENT_ROLE=${agentRole}`);
    lines.push(`      - TEMPLATE_ID=${svc.entry.template}`);
    lines.push("      - MCP_BASE_URL=http://swarm-api:3013");
    lines.push("      - YOLO=true");
    lines.push("      - SWARM_URL=http://swarm-api:3013");

    if (svc.entry.isLead) {
      lines.push("      - MAX_CONCURRENT_TASKS=1");
    }

    if (state.integrations.github) {
      lines.push(ENV_GITHUB_TOKEN);
      lines.push(ENV_GITHUB_EMAIL);
      lines.push(ENV_GITHUB_NAME);
    }

    if (state.integrations.gitlab) {
      lines.push(ENV_GITLAB_TOKEN);
      lines.push(ENV_GITLAB_EMAIL);
    }

    if (state.integrations.sentry) {
      lines.push(ENV_SENTRY_AUTH_TOKEN);
      lines.push(ENV_SENTRY_ORG);
    }

    lines.push("");
    lines.push("    ports:");
    lines.push(`      - "${port}:3000"`);
    lines.push("");
    lines.push("    volumes:");
    lines.push("      - swarm_logs:/app/logs");
    lines.push("      - swarm_shared:/app/shared");
    lines.push(`      - swarm_${svc.sanitizedName}:/app/agent`);
    lines.push("");
    lines.push("    restart: unless-stopped");
  }

  // ── Volumes section ──
  lines.push("");
  lines.push("volumes:");
  lines.push("  swarm_data:");
  lines.push("  swarm_logs:");
  lines.push("  swarm_shared:");
  for (const svc of expanded) {
    lines.push(`  swarm_${svc.sanitizedName}:`);
  }

  return `${lines.join("\n")}\n`;
}

import { expandServices } from "./service-names.ts";
import type { OnboardState } from "./types.ts";

/**
 * Generate a .env file string from onboard wizard state.
 * Uses real values from state (not placeholders).
 */
export function generateEnv(state: OnboardState): string {
  const expanded = expandServices(state.services, state.agentIds);
  const lines: string[] = [];

  // ── Core ──
  lines.push("# === Core ===");
  lines.push(`API_KEY=${state.apiKey}`);
  const port = state.apiPort || 3013;
  lines.push(`MCP_BASE_URL=http://localhost:${port}`);
  lines.push("APP_URL=http://localhost:5274");

  // ── Authentication ──
  lines.push("");
  lines.push("# === Authentication ===");
  if (state.credentialType === "api_key") {
    lines.push(`ANTHROPIC_API_KEY=${state.anthropicApiKey}`);
  } else {
    lines.push(`CLAUDE_CODE_OAUTH_TOKEN=${state.claudeOAuthToken}`);
  }

  // ── Integrations ──
  lines.push("");
  lines.push("# === Integrations ===");

  // GitHub
  if (state.integrations.github) {
    lines.push("");
    lines.push("# GitHub");
    lines.push(`GITHUB_TOKEN=${state.githubToken}`);
    lines.push(`GITHUB_EMAIL=${state.githubEmail}`);
    lines.push(`GITHUB_NAME=${state.githubName}`);
    lines.push("GITHUB_DISABLE=false");
  } else {
    lines.push("GITHUB_DISABLE=true");
  }

  // Slack
  if (state.integrations.slack) {
    lines.push("");
    lines.push("# Slack");
    lines.push(`SLACK_BOT_TOKEN=${state.slackBotToken}`);
    lines.push(`SLACK_APP_TOKEN=${state.slackAppToken}`);
    lines.push("SLACK_DISABLE=false");
  } else {
    lines.push("SLACK_DISABLE=true");
  }

  // GitLab
  if (state.integrations.gitlab) {
    lines.push("");
    lines.push("# GitLab");
    lines.push(`GITLAB_TOKEN=${state.gitlabToken}`);
    lines.push(`GITLAB_EMAIL=${state.gitlabEmail}`);
  }

  // Sentry
  if (state.integrations.sentry) {
    lines.push("");
    lines.push("# Sentry");
    lines.push(`SENTRY_AUTH_TOKEN=${state.sentryToken}`);
    lines.push(`SENTRY_ORG=${state.sentryOrg}`);
  }

  // ── Agent IDs ──
  lines.push("");
  lines.push("# === Agent IDs (for reference) ===");
  for (const svc of expanded) {
    lines.push(`# ${svc.name} = ${svc.agentId}`);
  }

  return `${lines.join("\n")}\n`;
}

